
-- Create reportes-pdf storage bucket
INSERT INTO storage.buckets (id, name, public, file_size_limit, allowed_mime_types)
VALUES ('reportes-pdf', 'reportes-pdf', false, 52428800, ARRAY['application/pdf']::text[])
ON CONFLICT (id) DO NOTHING;

-- Storage policies for reportes-pdf bucket
CREATE POLICY "reportes_storage_propio_select" ON storage.objects
  FOR SELECT TO authenticated
  USING (bucket_id = 'reportes-pdf' AND auth.uid()::text = (storage.foldername(name))[1]);

CREATE POLICY "reportes_storage_propio_insert" ON storage.objects
  FOR INSERT TO authenticated
  WITH CHECK (bucket_id = 'reportes-pdf' AND auth.uid()::text = (storage.foldername(name))[1]);

CREATE POLICY "reportes_storage_propio_delete" ON storage.objects
  FOR DELETE TO authenticated
  USING (bucket_id = 'reportes-pdf' AND auth.uid()::text = (storage.foldername(name))[1]);

